import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { WarrantyClaim } from '../../data/models';

interface LineBar {
  family: string;
  claims: number;
  pct: number;
}

@Component({
  selector: 'app-warranty',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './warranty.component.html',
  styleUrl: './warranty.component.css',
})
export class WarrantyComponent {
  readonly workflow: WarrantyClaim['status'][] = ['open', 'submitted', 'mfr-review', 'approved', 'closed'];
  readonly statuses: (WarrantyClaim['status'] | 'all')[] = ['all', 'open', 'submitted', 'mfr-review', 'approved', 'closed'];
  statusFilter = signal<WarrantyClaim['status'] | 'all'>('all');

  openClaims = computed(() =>
    this.seed.warrantyClaims().filter((c) => c.status !== 'closed').length,
  );
  breachedClaims = computed(() => this.seed.warrantyClaims().filter((c) => c.slaBreached));
  breachedCount = computed(() => this.breachedClaims().length);
  avgAge = computed(() => {
    const claims = this.seed.warrantyClaims();
    if (claims.length === 0) return 0;
    return Math.round(claims.reduce((s, c) => s + c.ageDays, 0) / claims.length);
  });

  filteredClaims = computed(() => {
    const f = this.statusFilter();
    if (f === 'all') return this.seed.warrantyClaims();
    return this.seed.warrantyClaims().filter((c) => c.status === f);
  });

  // Fabricated claim-rate distribution across product families (mockup).
  lineBars = computed<LineBar[]>(() => {
    const rows: LineBar[] = [
      { family: 'Tmax XT', claims: 5, pct: 0 },
      { family: 'SafeGear MV', claims: 3, pct: 0 },
      { family: 'VD4 / ADVAC', claims: 2, pct: 0 },
    ];
    const max = Math.max(1, ...rows.map((r) => r.claims));
    rows.forEach((r) => (r.pct = Math.round((r.claims / max) * 100)));
    return rows;
  });

  setStatus(status: WarrantyClaim['status'] | 'all'): void {
    this.statusFilter.set(status);
  }

  statusBadge(status: WarrantyClaim['status']): string {
    switch (status) {
      case 'open': return 'badge-warning';
      case 'submitted': return 'badge-info';
      case 'mfr-review': return 'badge-info';
      case 'approved': return 'badge-success';
      case 'closed': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  stepLabel(status: WarrantyClaim['status']): string {
    return status === 'mfr-review' ? 'MFR review' : status.charAt(0).toUpperCase() + status.slice(1);
  }

  constructor(public seed: SeedService) {}
}
